#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}

const int N=1e6+10,W=1e6,Mod=1e9+7;int dp[1<<24];long long ans=0;
inline void DN(int &x){x>=Mod?x-=Mod:0;} inline void UP(int &x){x<0?x+=Mod:0;}
inline void FMT(int *a){for(int i=0;i<24;++i)for(int S=0;S<(1<<24);++S)if((S>>i)&1)DN(dp[S]+=dp[S^(1<<i)]);}
int main()
{
	int n=read();rep(1,n,i)
	{
		char ch=getchar();int S=0;while(ch<'a'||ch>'z')ch=getchar();
		while(ch<='z'&&ch>='a'){if(ch<='x')S|=(1<<(ch-'a'));ch=getchar();}++dp[S];
	}
	FMT(dp);for(int S=0;S<(1<<24);++S)ans^=1ll*(n-dp[S])*(n-dp[S]);
	printf("%lld\n",ans);return 0;
}
